import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Perguntas frequentes dos jogadores","description":"Dúvidas mais frequentes dos jogadores e administradores de servidor sobre o Fabric.","frontmatter":{"title":"Perguntas frequentes dos jogadores","description":"Dúvidas mais frequentes dos jogadores e administradores de servidor sobre o Fabric.","files":[]},"headers":[],"relativePath":"pt_br/1.21.4/players/faq.md","filePath":"versions/1.21.4/translated/pt_br/players/faq.md","lastUpdated":1760721669000}`);var a={name:`pt_br/1.21.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Perguntas frequentes dos jogadores <a class="header-anchor" href="#h1" aria-label="Permalink to “Perguntas frequentes dos jogadores”">​</a></h1><p>Há muitas perguntas feitas com frequência, então compilamos uma lista delas aqui.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Quais versões do Minecraft são compatíveis com o Fabric? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Quais versões do Minecraft são compatíveis com o Fabric?”">​</a></h2><p>Oficialmente, o Fabric é compatível com todas as versões do Minecraft começando da snapshot <code>18w43b</code> em diante, e versões da <code>1.14</code> em diante.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Onde eu posso baixar mods publicados do Fabric? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Onde eu posso baixar mods publicados do Fabric?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Você deve sempre verificar se os mods são de fontes confiáveis. Visite o guia <a href="./finding-mods">Encontrando Mods Confiáveis</a> para mais informações.</p></div><p>A maioria dos autores publicam seus mods no <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e no CurseForge, no entando, alguns preferem publicá-los em seus sites pessoais, ou em outras plataformas, como um repositório GitHub.</p><h2 id="where-can-i-find-premade-fabric-modpacks" tabindex="-1">Onde eu posso achar modpacks pré-feitos para Fabric? <a class="header-anchor" href="#where-can-i-find-premade-fabric-modpacks" aria-label="Permalink to “Onde eu posso achar modpacks pré-feitos para Fabric?”">​</a></h2><p>Você pode achar modpacks para Fabric pré-feitos em várias plataformas, como:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};